-- Ward NPCs + preop optimization + progression + procedure locations.
-- Repo copy of migration ward_preop_progression (applied 2026-07-10, data_version 78).
-- Regenerate: node game/tools/gen_ward_sql.js > db/seed_ward_preop.sql

-- 1. procedure_game_params: level gate, standard-of-care location, preop rules
alter table public.procedure_game_params
  add column if not exists min_level int not null default 1,
  add column if not exists location text not null default 'ir_suite',
  add column if not exists preop jsonb not null default '{}';
do $$ begin
  alter table public.procedure_game_params
    add constraint procedure_game_params_location_check
    check (location in ('ir_suite','ct_suite','us_room','bedside'));
exception when duplicate_object then null; end $$;

-- 2. v_game_ready surfaces the gate + location to the client
create or replace view public.v_game_ready
with (security_invoker = true) as
select p.id, p.title, p.category_id, g.pacing, g.complexity, g.min_level, g.location
from public.procedures p
join public.procedure_game_params g on g.procedure_id = p.id
join public.vessel_maps vm          on vm.id = g.vessel_map_id
where p.status = 'published'
  and exists (select 1 from public.patient_generators pg
              where pg.procedure_id = p.id and pg.status = 'published')
  and exists (select 1 from public.complications c
              where (c.procedure_id = p.id or c.procedure_id is null)
                and c.status = 'published');

-- 3. Chest port: fluoroscopy suite [1]; preop CITED to [1]; min_level DESIGN.
update public.procedure_game_params set
  min_level = 1, location = 'ir_suite',
  preop = $steps${"labs":[{"id":"inr","label":"INR","kind":"max","limit":1.5,"required":true,"canBeMissing":true,"goalText":"goal < 1.5","cite":"Routine INR in all patients; goal < 1.5 [1]","derange":[1.7,3.4],"violation":{"score":[{"cat":"safety","delta":-6,"reason":"Proceeded with INR above the 1.5 goal for a moderate-bleeding-risk procedure without correction.","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":3,"basis":"MODELED multiplier"}]},"missingViolation":{"score":[{"cat":"safety","delta":-4,"reason":"Proceeded without a documented INR (routine for all patients).","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":1.5,"basis":"MODELED multiplier"}]}},{"id":"platelets","label":"Platelet count","kind":"min","limit":50,"required":false,"goalText":"transfuse if < 50 ×10⁹/L","cite":"Transfusion recommended for counts < 50,000/µL [1]","derange":[22,46],"violation":{"score":[{"cat":"safety","delta":-5,"reason":"Proceeded with platelets < 50 ×10⁹/L without transfusion.","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":3,"basis":"MODELED — mirrors the engine's multLow"}]}},{"id":"ptt","label":"PTT","kind":"max","limit":52.5,"required":false,"onlyIf":"on_anticoagulant","goalText":"< 1.5× control (normal 25–35 s)","cite":"PTT recommended on IV unfractionated heparin; < 1.5× control [1]","derange":[60,95],"violation":{"score":[{"cat":"safety","delta":-4,"reason":"Proceeded on anticoagulation with PTT > 1.5× control.","cite":"Preprocedure preparation [1]"}],"risk":[{"match":"hematoma|bleed","mult":2,"basis":"MODELED multiplier"}]}}],"contraindications":[{"id":"bacteremia","label":"Bacteremia / sepsis","cite":"Absolute contraindication [1]","emr":"Febrile to 38.9 °C overnight; 2/2 blood culture bottles growing gram-negative rods; on empiric antibiotics.","violation":{"score":[{"cat":"safety","delta":-15,"reason":"Implanted a subcutaneous port in an actively bacteremic patient.","cite":"Absolute contraindications [1]"}],"postop":"POD 5: port pocket infection with persistent bacteremia — device explanted, PICC bridge while clearing cultures."}},{"id":"cellulitis","label":"Cellulitis at the insertion site","cite":"Absolute contraindication [1]","emr":"Warm, indurated erythema over the right anterior chest and lower neck at the planned insertion site.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Placed the port through cellulitic skin.","cite":"Absolute contraindications [1]"}],"postop":"Early pocket infection tracking from the cellulitic entry — explant and IV antibiotics."}},{"id":"allergy","label":"Allergy to catheter material","cite":"Absolute contraindication [1]","emr":"Allergy list: documented severe reaction to the implant catheter material.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Implanted a device the patient has a documented material allergy to.","cite":"Absolute contraindications [1]"}],"postop":"Progressive local reaction around the pocket — device removed."}}]}$steps$::jsonb,
  case_steps = $steps$[{"n":1,"title":"Time-out & positioning","node":"rij_access","best":"timeout","prompt":"Pre-procedure. How do you begin?","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","upsize-035","closure-device"],"outcomes":{"timeout":{"label":"Time-out + US survey of the right IJ","note":"Correct — confirm patency/compressibility","score":[{"cat":"technical","delta":0,"reason":"Time-out and US survey performed."}],"ok":"Site confirmed; right IJ patent and compressible."},"skip":{"label":"Skip the time-out, patient's waiting","note":"Guideline violation","score":[{"cat":"technical","delta":-3,"reason":"Skipped surgical time-out.","cite":"Universal Protocol"}],"ok":"You proceed without a time-out."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol before a time-out."}],"narrative":"You do something else before the time-out."}},{"n":2,"title":"Venous access","node":"rij_access","best":"us","prompt":"Obtain venous access and secure a working wire to the SVC/IVC.","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","closure-device"],"outcomes":{"us":{"label":"US-guided micropuncture (21G), 0.018 → exchange → 0.035 Bentson","note":"Correct, lowest pneumothorax risk","needs":["micropuncture-needle-21g","mp-wire-018","transitional-dilator-5f","bentson-035-145"],"imaging":"tap","complication":{"name":"Pneumothorax","mult":1,"decline":{"sbpDrop":4,"spo2Drop":4,"rrRise":6}},"ok":"Clean US-guided access; 0.035 wire seated in the SVC.","hit":"Access obtained, but the post-access check shows a pneumothorax."},"us_glide":{"label":"US-guided micropuncture, exchange to 0.035 hydrophilic wire","note":"Equivalent safe technique — hydrophilic tracks easier (MODELED)","needs":["micropuncture-needle-21g","mp-wire-018","transitional-dilator-5f","glidewire-035-150"],"ownedOnly":true,"imaging":"tap","score":[{"cat":"technical","delta":0,"reason":"US-guided access; exchanged to a hydrophilic working wire (lubricity 9, MODELED)."}],"complication":{"name":"Pneumothorax","mult":1,"decline":{"sbpDrop":4,"spo2Drop":4,"rrRise":6}},"ok":"Clean US-guided access; hydrophilic wire glides to the SVC.","hit":"Access obtained, but the post-access check shows a pneumothorax."},"landmark":{"label":"Landmark stick (faster, no US)","note":"Higher pneumothorax risk","needs":["micropuncture-needle-21g","bentson-035-145"],"imaging":"tap","score":[{"cat":"technical","delta":-3,"reason":"Landmark venipuncture instead of real-time US guidance.","cite":"US guidance is standard of care [1]"}],"complication":{"name":"Pneumothorax","mult":5,"decline":{"sbpDrop":4,"spo2Drop":4,"rrRise":6}},"ok":"Landmark access happened to work this time.","hit":"Blind stick — the patient desaturates; pneumothorax."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"That maneuver does not establish venous access."}],"narrative":"That doesn't get you access."}},{"n":3,"title":"Create the pocket","node":"rij_access","best":"pocket","prompt":"Create the subcutaneous pocket on the pectoralis fascia.","blocked":["cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"outcomes":{"pocket":{"label":"Anesthetize, incise, develop a snug pocket","note":"Coag-dependent","complication":{"name":"Pocket hematoma","multFrom":"platelets","mult":1,"multLow":3,"multVeryLow":8,"decline":{"sbpDrop":6}},"ok":"Pocket created with good hemostasis.","hit":"Oozing in the pocket — a hematoma is developing."},"transfuse":{"label":"Order platelet transfusion first, then pocket","note":"Only meaningful if platelets are low","transfuse":true}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at pocket creation."}],"narrative":"That isn't how you create the pocket."}},{"n":4,"title":"Tunnel & measure","node":"right_bct","best":"measure","prompt":"Tunnel the catheter and set tip length to the cavoatrial junction.","blocked":["cat:embolization","cat:angioplasty","cat:recanalize"],"outcomes":{"measure":{"label":"Measure against the wire under fluoro, trim to CAJ","note":"Correct","needs":["port-catheter-8f"],"imaging":"tap","score":[{"cat":"technical","delta":0,"reason":"Tip length measured to the CAJ under fluoroscopy."}],"ok":"Catheter trimmed so the tip will sit at the CAJ."},"estimate":{"label":"Eyeball the length to save fluoro","note":"Malposition risk","needs":["port-catheter-8f"],"imaging":"reposition","setFlag":"malposition","score":[{"cat":"technical","delta":-4,"reason":"Estimated catheter length instead of fluoroscopic measurement — tip malposition."}],"ok":"Estimated length; the tip looks high — you'll need to reposition later."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at tunneling."}],"narrative":"That isn't the tunneling/measuring step."}},{"n":5,"title":"Sheath & catheter delivery","node":"svc","best":"valsalva_gentle","prompt":"Deliver the catheter through the peel-away sheath to the CAJ.","blocked":["cat:embolization","cat:angioplasty"],"outcomes":{"valsalva_gentle":{"label":"Valsalva/breath-hold, pinch sheath, gentle advance","note":"Correct technique","needs":["peelaway-sheath-9f"],"ok":"Sheath placed with air-embolism precautions; catheter advanced gently (resistance LOW). Tip at the CAJ."},"no_breathhold":{"label":"Advance briskly without a breath-hold","note":"Air-embolism risk","needs":["peelaway-sheath-9f"],"modeledEvent":{"name":"Air embolism","decline":{"sbpDrop":18,"spo2Drop":6,"rrRise":4},"note":"Open sheath without breath-hold entrained air (procedure step 5 precaution)."},"hit":"As the dilator comes out you hear a gasp — air embolism."},"forceful":{"label":"Seat it deep with a firm forceful push","note":"Watch tactile resistance","needs":["peelaway-sheath-9f"],"stress":{"device":"port-catheter-8f","node":"caj","force":"forceful","critScore":-4,"riskPct":40,"event":{"name":"CAJ perforation → pericardial effusion","decline":{"sbpDrop":30,"spo2Drop":2,"rrRise":4},"note":"Over-forceful advance at the fragile cavoatrial junction against critical resistance."},"hit":"Sudden give, then hypotension — you've perforated the CAJ.","critOk":"It seats deep — resistance was CRITICAL but it held this time. Don't push against that."},"ok":"It seats deep; resistance was high but held."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at catheter delivery."}],"narrative":"That isn't the delivery step."}},{"n":6,"title":"Connect & test","node":"caj","best":"aspirate","prompt":"Connect the port and test it.","blocked":["cat:embolization","cat:angioplasty"],"outcomes":{"aspirate":{"label":"Lock to stem; Huber access; aspirate + flush each lumen","note":"Correct","needs":["huber-needle-20g"],"score":[{"cat":"technical","delta":0,"reason":"Brisk blood return and free flush confirmed."}],"ok":"Brisk blood return, free flush, no pocket swelling."},"skip":{"label":"Skip the aspiration test, it looked fine","note":"Guideline violation","score":[{"cat":"technical","delta":-3,"reason":"Skipped the aspiration/flush patency test."}],"ok":"You skip the patency check."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at port testing."}],"narrative":"That isn't the connect/test step."}},{"n":7,"title":"Confirm tip & close","node":"caj","best":"dsa","prompt":"Confirm final tip position and close.","outcomes":{"dsa":{"label":"DSA spot to document CAJ tip, then two-layer close","note":"Correct","imaging":"dsa","contrastMl":3,"ifFlag":"malposition","ifFlagScore":[{"cat":"technical","delta":-3,"reason":"Malpositioned tip required repositioning before closure."}],"ifFlagImaging":"reposition","ifFlagNarrative":"Spot shows the tip was high; repositioned to the CAJ, then closed.","elseScore":[{"cat":"technical","delta":0,"reason":"Fluoroscopic spot documents CAJ tip without kinks."}],"elseNarrative":"Tip confirmed at the CAJ; pocket closed in two layers."},"noconfirm":{"label":"Close without a confirmatory image","note":"Misses malposition","score":[{"cat":"technical","delta":-6,"reason":"Closed without documenting final tip position."}],"ifFlag":"malposition","ifFlagScore":[{"cat":"safety","delta":0,"reason":"Undocumented malpositioned tip left in place."}],"narrative":"You close without a confirmatory spot film."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"Off-protocol at closure."}],"narrative":"That isn't the confirm/close step."}}]$steps$::jsonb
where procedure_id = 'chest-port';

-- UFE: IR suite. Preop rules MODELED pending citation. min_level 2 DESIGN.
update public.procedure_game_params set
  min_level = 2, location = 'ir_suite',
  preop = $steps${"labs":[{"id":"inr","label":"INR","kind":"max","limit":1.5,"required":true,"canBeMissing":true,"goalText":"goal < 1.5 (moderate bleeding risk)","cite":"MODELED — pending citation (SIR moderate-risk convention)","derange":[1.7,3],"violation":{"score":[{"cat":"safety","delta":-6,"reason":"Proceeded with INR above the 1.5 goal without correction.","cite":"MODELED — pending citation"}],"risk":[{"match":"hematoma|bleed|puncture","mult":3,"basis":"MODELED multiplier"}]},"missingViolation":{"score":[{"cat":"safety","delta":-4,"reason":"Proceeded without a documented INR.","cite":"MODELED — pending citation"}],"risk":[{"match":"hematoma|bleed|puncture","mult":1.5,"basis":"MODELED multiplier"}]}},{"id":"platelets","label":"Platelet count","kind":"min","limit":50,"required":false,"goalText":"transfuse if < 50 ×10⁹/L","cite":"MODELED — pending citation (SIR moderate-risk convention)","derange":[24,46],"violation":{"score":[{"cat":"safety","delta":-5,"reason":"Proceeded with platelets < 50 ×10⁹/L without transfusion.","cite":"MODELED — pending citation"}],"risk":[{"match":"hematoma|bleed|puncture","mult":3,"basis":"MODELED multiplier"}]}}],"contraindications":[{"id":"pregnancy","label":"Viable pregnancy","cite":"MODELED — pending citation (standard UFE contraindication)","emr":"This morning's β-hCG returned positive; bedside ultrasound shows an early intrauterine pregnancy.","violation":{"score":[{"cat":"safety","delta":-15,"reason":"Embolized the uterine arteries of a pregnant patient.","cite":"MODELED — pending citation"}],"postop":"Pregnancy loss attributed to uterine devascularization — root-cause analysis opened."}},{"id":"pelvic_infection","label":"Active pelvic infection","cite":"MODELED — pending citation (standard UFE contraindication)","emr":"Purulent cervical discharge with uterine tenderness; WBC 15.8 — gynecology is treating active PID.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Embolized a uterus with active pelvic infection.","cite":"MODELED — pending citation"}],"postop":"Pyometra requiring hysterectomy — infected, devascularized tissue."}},{"id":"gyn_malignancy","label":"Suspected gynecologic malignancy","cite":"MODELED — pending citation (standard UFE contraindication)","emr":"Rapidly enlarging uterine mass with irregular enhancement and ascites — malignancy not yet excluded; biopsy pending.","violation":{"score":[{"cat":"safety","delta":-12,"reason":"Embolized a mass suspicious for malignancy before tissue diagnosis.","cite":"MODELED — pending citation"}],"postop":"Final pathology: leiomyosarcoma — embolization delayed the oncologic diagnosis."}}]}$steps$::jsonb,
  case_steps = $steps$[{"n":1,"title":"Time-out & planning","node":"cfa_access","best":"timeout","prompt":"Symptomatic fibroids, MRI reviewed. Begin the case.","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","place-sheath","upsize-sheath","long-sheath","closure-device"],"teaching":"Confirm symptomatic fibroids, patent uterine ostia, and no dominant ovarian supply before starting.","outcomes":{"timeout":{"label":"Pre-procedure time-out; confirm MRI, symptoms, consent","note":"Correct","ok":"MRI shows dominant fundal fibroids with patent uterine arteries. Consent confirmed."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Skipped the pre-procedure time-out."}],"narrative":"You skip the checklist and press on."}},{"n":2,"title":"Femoral access","node":"cfa_access","best":"us-micropuncture","prompt":"Obtain arterial access and place a working sheath.","blocked":["cat:wire","cat:catheter","cat:embolization","cat:angioplasty","cat:recanalize","closure-device"],"teaching":"Ultrasound-guided common femoral access lowers access-site complications.","outcomes":{"us-micropuncture":{"label":"Ultrasound-guided common femoral access, 5F sheath","note":"Standard of care","needs":["micropuncture-needle-21g","vascular-sheath-5f"],"imaging":"us","ok":"Single anterior-wall CFA puncture under ultrasound; 5F sheath placed."},"landmark":{"label":"Landmark femoral stick without ultrasound","note":"Off-standard","needs":["micropuncture-needle-21g","vascular-sheath-5f"],"score":[{"cat":"technical","delta":-3,"reason":"Femoral access without ultrasound guidance.","cite":"US-guided access reduces access-site complications"}],"ok":"Access obtained by palpation; sheath placed."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"That does not obtain arterial access."}],"narrative":"That won't get you into the femoral artery."}},{"n":3,"title":"Pelvic arteriogram","node":"aortic_bifurc","best":"dsa","prompt":"Map the uterine arteries before selecting.","blocked":["cat:embolization","cat:angioplasty","cat:recanalize"],"teaching":"A diagnostic pelvic run identifies the uterine origins and any ovarian collateral supply.","outcomes":{"dsa":{"label":"Pelvic DSA through a flush catheter","note":"Correct roadmap","needs":["pigtail-flush-5f","bentson-035-145"],"imaging":"dsa","contrastMl":12,"ok":"Pelvic arteriogram maps both uterine arteries; no dominant ovarian supply."},"fluoro":{"label":"A quick fluoro spot instead of a full run","note":"Inadequate roadmap","imaging":"fluoro","score":[{"cat":"technical","delta":-3,"reason":"No diagnostic pelvic arteriogram before selection."}],"ok":"You skip the full run and start poking around."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"No pelvic roadmap obtained."}],"narrative":"You proceed without mapping the anatomy."}},{"n":4,"title":"Select the uterine artery","node":"contra_iia","best":"reform","prompt":"Catheterize the (contralateral) uterine artery.","blocked":["cat:embolization","cat:angioplasty"],"teaching":"A reverse-curve catheter reforms to select the sharply reflexed uterine origin up-and-over the bifurcation.","outcomes":{"reform":{"label":"Reform a reverse-curve catheter into the uterine artery","note":"Correct","needs":["sos-omni-5f","stiff-glidewire-035"],"imaging":"fluoro","ok":"Reverse curve reformed; up-and-over to the contralateral internal iliac, then into the uterine artery."},"advance-cath":{"label":"Push a straight catheter at the origin","note":"Wrong shape for this angle","score":[{"cat":"technical","delta":-3,"reason":"A straight catheter cannot hold the sharply reflexed uterine origin."}],"ok":"The straight catheter keeps prolapsing out — no stable selection."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at uterine selection."}],"narrative":"That doesn't select the uterine artery."}},{"n":5,"title":"Superselect","node":"uterine_origin","best":"superselect","prompt":"Position a microcatheter for embolization.","teaching":"Advancing distal to the cervicovaginal branch protects nontarget bladder/vaginal territory.","outcomes":{"superselect":{"label":"Microcatheter distal to the cervicovaginal branch","note":"Correct — protects nontarget territory","needs":["microcatheter-27-150"],"imaging":"fluoro","ok":"Microcatheter parked in the horizontal segment, beyond the cervicovaginal branch."},"advance-micro":{"label":"Microcatheter only to the proximal uterine artery","note":"Proximal — higher nontarget risk","needs":["microcatheter-27-150"],"imaging":"fluoro","setFlag":"proximal_embo","score":[{"cat":"technical","delta":-2,"reason":"Proximal microcatheter position raises nontarget/ovarian collateral risk."}],"ok":"Microcatheter sits proximally, near the cervicovaginal origin."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol at superselection."}],"narrative":"That doesn't superselect the uterine artery."}},{"n":6,"title":"Embolize to near-stasis","node":"uterine_target","best":"particles","prompt":"Devascularize the fibroids.","teaching":"Calibrated spheres to a slow-flow, pruned-tree endpoint — stop before stasis to limit reflux.","outcomes":{"particles":{"label":"Inject calibrated microspheres to a pruned-tree endpoint","note":"Correct endpoint","needs":["microspheres-500-700"],"imaging":"fluoro","contrastMl":6,"complication":{"name":"Nontarget embolization (bladder, vagina, skin)","mult":1,"decline":{"sbpDrop":2}},"ok":"500–700 µm spheres to a slow-flow, pruned-tree endpoint.","hit":"A little reflux — some spheres reach the bladder/vaginal branches."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"That does not embolize the fibroid bed appropriately (e.g., a proximal coil leaves collateral supply)."}],"narrative":"That isn't the right way to devascularize the fibroids."}},{"n":7,"title":"Contralateral side","node":"uterine_target","best":"reform","prompt":"Treat the other uterine artery.","teaching":"Bilateral treatment is standard — unilateral UFE has high recurrence.","outcomes":{"reform":{"label":"Select and embolize the opposite uterine artery to the same endpoint","note":"Bilateral is standard","imaging":"fluoro","contrastMl":6,"complication":{"name":"Ovarian insufficiency","mult":1,"decline":{}},"ok":"Contralateral uterine artery selected and embolized to near-stasis; bilateral treatment complete.","hit":"Diffuse embolization compromises some ovarian arterial supply."},"single-side":{"label":"Treat only the accessed side; skip the contralateral artery","note":"Undertreatment","score":[{"cat":"technical","delta":-5,"reason":"Unilateral UFE — high recurrence; both uterine arteries should be treated."}],"ok":"You stop after one side."}},"default":{"score":[{"cat":"technical","delta":-3,"reason":"Off-protocol before treating the second side."}],"narrative":"That doesn't address the contralateral uterine artery."}},{"n":8,"title":"Completion & closure","node":"cfa_access","best":"closure-device","prompt":"Finish the case.","teaching":"A completion run documents bilateral devascularization; both closure devices and manual pressure are acceptable.","outcomes":{"closure-device":{"label":"Completion pelvic run, then a closure device","note":"Correct","needs":["collagen-plug-closure"],"imaging":"dsa","contrastMl":5,"ok":"Completion run confirms bilateral devascularization; collagen-plug closure with good hemostasis. Expect post-embolization syndrome (cramping, low-grade fever) — managed with NSAIDs/anti-emetics on the ward."},"manual-closure":{"label":"Completion run, then hold manual pressure","note":"Also acceptable","imaging":"dsa","contrastMl":5,"ok":"Completion run good; ~15 minutes of manual pressure to hemostasis."}},"default":{"score":[{"cat":"technical","delta":-4,"reason":"Closed without a completion angiogram."}],"narrative":"You close without documenting the result."}}]$steps$::jsonb
where procedure_id = 'uterine-fibroid-embolization';

-- 4. game_config
insert into public.game_config (key, value, data_class, citation, description) values
 ('progression', $steps${"levels":[{"level":1,"xp":0,"title":"PGY-2 Resident"},{"level":2,"xp":120,"title":"PGY-4 Resident"},{"level":3,"xp":300,"title":"IR Fellow"},{"level":4,"xp":600,"title":"Junior Attending"},{"level":5,"xp":1000,"title":"Attending"},{"level":6,"xp":1600,"title":"Division Chief"}],"xp_per_score_pct":0.5,"turn_down_xp":10,"turn_down_clout":5,"wrong_turn_down_clout":-10,"fail_clout":{"bailed":-5,"takeover":-5,"kicked":-3}}$steps$::jsonb, 'design', '',
  'XP/level ladder gating which procedures spawn in ward beds. All DESIGN.'),
 ('lab_catalog', $steps${"labs":[{"id":"inr","name":"INR","unit":"","normal":[0.9,1.2],"fixNote":"Anticoagulation held / plasma given — INR rechecked."},{"id":"pt","name":"PT","unit":"s","normal":[11,13.5],"fixNote":"PT rechecked."},{"id":"ptt","name":"PTT","unit":"s","normal":[25,35],"fixNote":"Heparin held per protocol — PTT rechecked."},{"id":"platelets","name":"Platelet count (CBC)","unit":"×10⁹/L","normal":[150,400],"fixNote":"Platelets transfused — post-transfusion count rechecked."},{"id":"hemoglobin","name":"Hemoglobin (CBC)","unit":"g/dL","normal":[12,16],"fixNote":"CBC rechecked."},{"id":"creatinine","name":"Creatinine (BMP)","unit":"mg/dL","normal":[0.6,1.3],"fixNote":"BMP rechecked after gentle hydration."},{"id":"fibrinogen","name":"Fibrinogen","unit":"mg/dL","normal":[200,400],"fixNote":"Cryoprecipitate given if low — fibrinogen rechecked."},{"id":"abg","name":"ABG","unit":"","normal":null,"note":"pH 7.35–7.45 · pO₂ 80–100 · pCO₂ 35–45","fixNote":"ABG resulted."},{"id":"type_screen","name":"Type & Screen","unit":"","normal":null,"fixNote":"Type & screen on file — blood available."}]}$steps$::jsonb, 'modeled', '',
  'Orderable preop labs + reference intervals (standard reference ranges; MODELED).'),
 ('ward', $steps${"beds":6,"respawn_min_s":120,"respawn_max_s":300,"p_contra":0.12,"p_deranged":0.4,"p_missing":0.22}$steps$::jsonb, 'design', '',
  'Ward bed count, respawn window (compressed 2-5 min; spec 15-30 min), spawn mix.'),
 ('attending_dialogue', $steps${"blocked":["Excuse me lad, but aren't you missing a step?","Think it through — what has to happen before that is even possible?","You physically cannot do that yet. What comes first?","Stop. Look at the field. Tell me what is missing.","You clearly need to read a book. I am taking over this case."],"hints":["The attending pokes their head in and points at the field.","The attending sighs and walks you through it.","The attending taps the monitor meaningfully.","The attending narrates the step like you're a med student.","The attending does everything but grab your hands."],"kicked":"That's five hints. Scrub out, go read the chapter, and come back when you can talk me through the steps.","strike_cap":5,"hint_cap":5}$steps$::jsonb, 'design', '',
  'Attending escalation lines for blocked steps, hints, and the 5-strike takeover.')
on conflict (key) do update
  set value = excluded.value, data_class = excluded.data_class, description = excluded.description;
